const WeatherCard = ({
  city,
  icon,
  temperature,
  feelsLike,
  condition,
  wind,
  humidity,
  aqi
}) => {
  return (
    <div className="card">
      <h2>{city}</h2>
      <img src={icon} alt="weather icon" />
      <p>{temperature}</p>
      <p>{feelsLike}</p>
      <p>{condition}</p>
      <p>{wind}</p>
      <p>{humidity}</p>
      <p>{aqi}</p>
    </div>
  );
};
const getAQILabel = (value) => {
  if (value === 1) return "Good";
  if (value === 2) return "Moderate";
  if (value === 3) return "Unhealthy (Sensitive)";
  if (value === 4) return "Unhealthy";
  if (value === 5) return "Very Unhealthy";
  return "Hazardous";
};

const getAQIColor = (value) => {
  if (value === 1) return "#00e400"; // Green
  if (value === 2) return "#ffff00"; // Yellow
  if (value === 3) return "#ff7e00"; // Orange
  if (value === 4) return "#ff0000"; // Red
  if (value === 5) return "#8f3f97"; // Purple
  return "#7e0023"; // Maroon
};

export default WeatherCard;
